/*==================== 使用介绍 ====================
作责：小月 https://github.com/xiaoyue421
二改叼毛：vullfin https://github.com/rpvvn

此代码仅限于QQ，因为不玩儿微信

抓包软件下载
Github：https://github.com/wanghongenpin/proxypin
国内下载： https://gitee.com/wanghongenpin/proxypin/releases
iOS App Store： https://apps.apple.com/app/proxypin/id6450932949
Android Google Play：https://play.google.com/store/apps/details?id=com.network.proxy

先安装证书，这都不会的话就别玩了😂😂😂

    流程点击设置
        ↓
    HTTPS代理
        ↓
    安装根证书
        ↓
    用户证书
        ↓
      下载

根据提示自己导入,然后再配置是下面的

配置请求重写，教程如下

名称：自己随便设置
URL：gate-obt.nqf.qq.com/*
行为：重定向
重定向为到：http://127.0.0.1

配置脚本，教程如下
(ps：记得在QQ界面动态中右上角4个小方框编辑 
管理 添加购物和qq农场，这个购物必须要有，不用点也不用干啥，就必须和你的qq农场小程序同时在一个界面里。
名称：自己随便设置

(特别注意，下面的链接是可以添加的，多个！！！！)
URL(s)：
wss://gate-obt.nqf.qq.com/prod/ws
https://gate-obt.nqf.qq.com/prod/ws
gate-obt.nqf.qq.com/prod/ws*
https://h.trace.qq.com/kv
h.trace.qq.com/kv*

类型：本地
脚本先点最右边的删除按钮
重新粘贴此脚本

如果想查看日志
点击脚本 > 日志 > 切换首页，点开始抓包 > 切换到日志界面即可
==================== 使用介绍 ====================*/
async function onRequest(context, request) {
    const TARGET_HOST = "gate-obt.nqf.qq.com";
    const TARGET_PATH = "/prod/ws";
    const QQ_HOST = "h.trace.qq.com";
    const QQ_PATH = "/kv";
    const API_URL = "http://改成你的地址/api/accounts";
    const PASSWORD = "改成你的后台密码";
    
    context.session.uinRecords ??= {};
    context.session.lastUin ??= null;
    
    // 1. 处理QQ跟踪请求，提取UIN
    if (request.host === QQ_HOST && request.path.includes(QQ_PATH)) {
        const uin = request.queries.uin;
        if (/^\d+$/.test(uin)) {
            const now = Date.now();
            if (!context.session.uinRecords[uin]) {
                context.session.uinRecords[uin] = { firstSeen: now, lastSeen: now, count: 1 };
                console.log(`🆕 发现新UIN: ${uin}`);
            } else {
                context.session.uinRecords[uin].lastSeen = now;
                context.session.uinRecords[uin].count++;
            }
            context.session.lastUin = uin;
            
            // 清理过期记录
            Object.keys(context.session.uinRecords).forEach(u => {
                if (now - context.session.uinRecords[u].lastSeen > 5 * 60 * 1000) {
                    delete context.session.uinRecords[u];
                    console.log(`🧹 清理过期UIN: ${u}`);
                }
            });
        }
        return request;
    }
    
    // 2. 处理WS请求
    if (request.host === TARGET_HOST && request.path.includes(TARGET_PATH)) {
        const { code, platform } = request.queries;
        if (platform !== 'qq' || !code) return request;
        
        const currentUin = context.session.lastUin;
        if (!currentUin) {
            console.log('⏭️ 没有活动的UIN，跳过处理');
            return null;
        }
        
        console.log(`🎯 处理UIN: ${currentUin}, Code: ${code.substring(0, 8)}...`);
        
        const codeKey = `lastCode_${currentUin}`;
        if (context.session[codeKey] === code) {
            console.log('⏭️ 重复code, 跳过');
            return null;
        }
        context.session[codeKey] = code;
        
        const lockKey = `processing_${currentUin}`;
        if (context.session[lockKey]) {
            console.log(`⏸️ ${currentUin} 正在处理中，跳过`);
            return null;
        }
        context.session[lockKey] = true;
        
        // 异步处理
        (async () => {
            try {
                const getToken = async () => {
                    const res = await fetch(API_URL.replace('/accounts', '/login'), {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json' },
                        body: JSON.stringify({ password: PASSWORD })
                    });
                    if (!res.ok) throw new Error(`登录失败: ${res.status}`);
                    const data = await res.json();
                    if (data.ok && data.data?.token) return data.data.token;
                    throw new Error('Token获取失败');
                };
                
                const getAccount = async (uin, token) => {
                    try {
                        const res = await fetch(API_URL, { headers: { 'x-admin-token': token } });
                        if (res.ok) {
                            const data = await res.json();
                            return (data.data?.accounts || []).find(a => a.name === uin) || null;
                        }
                    } catch (e) {
                        console.error('❌ 查询账户失败:', e.message);
                    }
                    return null;
                };
                
                const registerAccount = async (uin, platform, code, token) => {
                    if (!/^\d+$/.test(uin)) {
                        console.log(`❌ 无效UIN: ${uin}`);
                        return null;
                    }
                    try {
                        const res = await fetch(API_URL, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json', 'x-admin-token': token },
                            body: JSON.stringify({ name: uin, uin, qq: uin, platform, loginType: 'manual', code })
                        });
                        if (res.ok) {
                            console.log(`✅ 新账户创建成功: ${uin}`);
                            return (await res.json()).data;
                        }
                        console.error(`❌ 账户创建失败: ${await res.text()}`);
                    } catch (e) {
                        console.error('❌ 账户创建异常:', e.message);
                    }
                    return null;
                };
                
                const updateAccount = async (account, newCode, token) => {
                    try {
                        const res = await fetch(API_URL, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json', 'x-admin-token': token },
                            body: JSON.stringify({ id: account.id, code: newCode })
                        });
                        if (!res.ok) throw new Error(`更新失败: ${await res.text()}`);
                        console.log(`✅ ${account.name} 账户更新成功`);
                        return true;
                    } catch (e) {
                        console.error('❌ 账户更新失败:', e.message);
                        return false;
                    }
                };
                
                const restartAccount = async (accountId, token) => {
                    try {
                        console.log('🚀 停止账号...');
                        const stopRes = await fetch(`${API_URL}/${accountId}/stop`, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json', 'x-admin-token': token },
                            body: JSON.stringify({})
                        });
                        console.log(`🚀 停止响应: ${stopRes.status} ${stopRes.statusText}`);
                        
                        console.log('🚀 启动账号...');
                        const startRes = await fetch(`${API_URL}/${accountId}/start`, {
                            method: 'POST',
                            headers: { 'Content-Type': 'application/json', 'x-admin-token': token },
                            body: JSON.stringify({})
                        });
                        console.log(`🚀 启动响应: ${startRes.status} ${startRes.statusText}`);
                    } catch (e) {
                        console.error('❌ 重启失败:', e.message);
                    }
                };
                
                console.log('🔄 开始处理账户逻辑...');
                const token = await getToken();
                const account = await getAccount(currentUin, token);
                
                if (account) {
                    if (account.code !== code) {
                        console.log(`🔄 检测到code变化: ${currentUin}`);
                        console.log(`   旧code: ${account.code.substring(0, 8)}...`);
                        console.log(`   新code: ${code.substring(0, 8)}...`);
                        if (await updateAccount(account, code, token)) {
                            await restartAccount(account.id, token);
                        }
                    } else {
                        console.log(`✅ ${currentUin} 账户已是最新状态`);
                    }
                } else {
                    console.log(`🆕 未找到账户 ${currentUin}，创建新账户`);
                    const newAccount = await registerAccount(currentUin, platform, code, token);
                    if (newAccount) await restartAccount(newAccount.id, token);
                }
            } catch (e) {
                console.error('💥 处理流程异常:', e.message);
            } finally {
                delete context.session[lockKey];
            }
        })();
        
        return null;
    }
    
    return request;
}

async function onResponse(context, request, response) {
    return response;
}
